import React, { useEffect, useState, useRef, useMemo } from 'react';
import type { Activity } from '../types';
import { ActivityStatus } from '../types';

interface ActivityGanttViewProps {
    activities: Activity[];
    onEdit: (activity: Activity) => void;
}

const STATUS_COLORS: { [key in ActivityStatus]: string } = {
    [ActivityStatus.Open]: 'bg-gray-600',
    [ActivityStatus.NaoExecutado]: 'bg-red-600',
    [ActivityStatus.EmProgresso]: 'bg-blue-600',
    [ActivityStatus.ExecutadoParcialmente]: 'bg-yellow-500',
    [ActivityStatus.Closed]: 'bg-green-600',
};

const GanttBar: React.FC<{ activity: Activity, chartStart: number, hourWidth: number, height: number, onClick: () => void }> = ({ activity, chartStart, hourWidth, height, onClick }) => {
    const start = new Date(activity.horaInicio).getTime();
    const end = new Date(activity.horaFim).getTime();

    // Calculate position relative to chart start
    // Ensure we account for strict pixel arithmetic to align with the grid
    const diffMs = start - chartStart;
    const durationMs = end - start;

    // 1 hour = hourWidth pixels
    // 1 ms = hourWidth / 3600000 pixels
    const pxPerMs = hourWidth / 3600000;

    const left = diffMs * pxPerMs;
    const width = Math.max(durationMs * pxPerMs, 4); // Min width 4px

    const barColor = STATUS_COLORS[activity.status] || 'bg-gray-500';

    return (
        <div 
            className={`absolute top-1/2 -translate-y-1/2 rounded-sm opacity-90 hover:opacity-100 transition-all flex items-center px-2 text-[10px] font-medium text-white shadow-sm ${barColor} cursor-pointer hover:ring-1 hover:ring-white hover:z-10 overflow-hidden whitespace-nowrap`}
            style={{ 
                left: `${left}px`, 
                width: `${width}px`, 
                height: `${height * 0.7}px`, // Bar uses 70% of row height
            }}
            title={`${activity.tag} - ${activity.descricao}\n${new Date(activity.horaInicio).toLocaleString()} - ${new Date(activity.horaFim).toLocaleString()}`}
            onClick={(e) => {
                e.stopPropagation();
                onClick();
            }}
        >
            {width > 40 && <span className="truncate">{activity.tag}</span>}
        </div>
    );
};

export const ActivityGanttView: React.FC<ActivityGanttViewProps> = ({ activities, onEdit }) => {
    const [currentTime, setCurrentTime] = useState(new Date());
    const [hourWidth, setHourWidth] = useState(60); // Zoom level
    const [isCompact, setIsCompact] = useState(false); // Row height toggle
    const containerRef = useRef<HTMLDivElement>(null);

    const rowHeight = isCompact ? 28 : 45; 
    const yAxisWidth = 220; 

    useEffect(() => {
        const timer = setInterval(() => {
            setCurrentTime(new Date());
        }, 60000);
        return () => clearInterval(timer);
    }, []);

    // --- Timeline Calculation ---
    const { chartStart, chartEnd, days } = useMemo(() => {
        if (activities.length === 0) {
            const now = new Date();
            const start = new Date(now); start.setHours(0,0,0,0);
            const end = new Date(now); end.setHours(23,59,59,999);
            return { chartStart: start.getTime(), chartEnd: end.getTime(), days: [start] };
        }

        const startTimes = activities.map(a => new Date(a.horaInicio).getTime());
        const endTimes = activities.map(a => new Date(a.horaFim).getTime());

        const minTime = Math.min(...startTimes);
        const maxTime = Math.max(...endTimes);

        // Start at 00:00 of the first day
        const startDate = new Date(minTime);
        startDate.setHours(0, 0, 0, 0);

        // End at 23:59 of the last day
        const endDate = new Date(maxTime);
        endDate.setHours(23, 59, 59, 999);

        // Generate array of days
        const daysArr = [];
        let current = new Date(startDate);
        while (current <= endDate) {
            daysArr.push(new Date(current));
            current.setDate(current.getDate() + 1);
        }

        return { chartStart: startDate.getTime(), chartEnd: endDate.getTime(), days: daysArr };
    }, [activities]);

    const totalHours = days.length * 24;
    const totalChartWidth = totalHours * hourWidth;
    const pxPerMs = hourWidth / 3600000;

    // Scroll to Now
    const scrollToNow = () => {
        if (containerRef.current) {
            const nowMs = new Date().getTime();
            if (nowMs >= chartStart && nowMs <= chartEnd) {
                const diff = nowMs - chartStart;
                const left = diff * pxPerMs;
                const scrollLeft = left - (containerRef.current.clientWidth / 2) + yAxisWidth;
                containerRef.current.scrollTo({ left: Math.max(0, scrollLeft), behavior: 'smooth' });
            } else {
                alert("A data atual está fora do intervalo de atividades exibido.");
            }
        }
    };

    // --- Render Helpers ---

    // Current Time Line
    const renderCurrentTimeLine = () => {
        const nowMs = currentTime.getTime();
        if (nowMs < chartStart || nowMs > chartEnd) return null;

        const left = (nowMs - chartStart) * pxPerMs;
        const label = currentTime.toLocaleTimeString([], {hour: '2-digit', minute: '2-digit'});

        return (
            <div 
                className="absolute top-0 bottom-0 w-[2px] bg-red-500 z-20 shadow-[0_0_4px_rgba(239,68,68,0.6)] pointer-events-none" 
                style={{ 
                    left: `${left}px`,
                    transform: 'translateX(-50%)' 
                }}
            >
                <div className="absolute -top-0 -translate-x-1/2 bg-red-600 text-white text-[9px] px-1 py-0.5 rounded-b font-bold whitespace-nowrap z-30">
                    {label}
                </div>
            </div>
        );
    };

    if (activities.length === 0) {
        return <div className="text-center p-8 bg-white/80 dark:bg-gray-800/80 backdrop-blur-md rounded-lg shadow text-gray-800 dark:text-gray-200">Nenhuma atividade para exibir no gráfico de Gantt.</div>;
    }

    // Sort strictly by Date first.
    // Changing status should NOT move the activity if date is same.
    const sortedActivities = [...activities].sort((a,b) => {
        return new Date(a.horaInicio).getTime() - new Date(b.horaInicio).getTime();
    });

    return (
        <div className="flex flex-col h-[80vh] bg-white/90 dark:bg-gray-800/90 backdrop-blur-md rounded-lg shadow border border-gray-200 dark:border-gray-700">

            {/* Controls Toolbar */}
            <div className="p-2 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between bg-gray-50 dark:bg-gray-800 rounded-t-lg">
                <div className="flex items-center space-x-4">
                    <div className="flex items-center space-x-1 bg-white dark:bg-gray-700 rounded-md border dark:border-gray-600 p-0.5">
                        <button 
                            onClick={() => setHourWidth(prev => Math.max(20, prev - 10))}
                            className="px-2 py-1 text-xs font-bold text-gray-600 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-600 rounded"
                            title="Diminuir Zoom"
                        >
                            -
                        </button>
                        <span className="text-xs text-gray-500 dark:text-gray-400 min-w-[60px] text-center">Zoom: {hourWidth}px</span>
                        <button 
                            onClick={() => setHourWidth(prev => Math.min(200, prev + 10))}
                            className="px-2 py-1 text-xs font-bold text-gray-600 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-600 rounded"
                            title="Aumentar Zoom"
                        >
                            +
                        </button>
                    </div>

                    <label className="flex items-center cursor-pointer space-x-2 text-xs text-gray-700 dark:text-gray-300">
                        <input 
                            type="checkbox" 
                            checked={isCompact} 
                            onChange={(e) => setIsCompact(e.target.checked)} 
                            className="rounded text-primary-600 focus:ring-primary-500 dark:bg-gray-700 dark:border-gray-600"
                        />
                        <span>Compacto</span>
                    </label>
                </div>

                <button 
                    onClick={scrollToNow}
                    className="px-3 py-1 text-xs bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300 rounded border border-red-200 dark:border-red-800 hover:bg-red-200 transition-colors"
                >
                    Ir para Agora
                </button>
            </div>

            {/* Main Chart Area */}
            <div className="flex-1 overflow-auto relative" ref={containerRef}>
                {/* 
                   KEY LAYOUT FIX:
                   Ensure the container for rows and grid is exactly the same width.
                   Grid acts as absolute background to the relative content container.
                */}
                <div className="relative inline-block" style={{ minWidth: '100%' }}>

                    {/* Header Container (Sticky) */}
                    <div className="sticky top-0 z-30 bg-gray-100 dark:bg-gray-700 shadow-sm">

                        {/* Row 1: Days */}
                        <div className="flex border-b border-gray-300 dark:border-gray-600">
                            {/* Empty corner for Y axis */}
                            <div 
                                style={{ width: `${yAxisWidth}px` }} 
                                className="flex-shrink-0 sticky left-0 bg-gray-200 dark:bg-gray-800 border-r border-gray-300 dark:border-gray-600 z-40"
                            ></div>

                            {/* Days Loop */}
                            {days.map(day => (
                                <div 
                                    key={day.toISOString()}
                                    style={{ width: `${24 * hourWidth}px` }}
                                    className="flex-shrink-0 text-center text-xs font-bold text-gray-700 dark:text-gray-200 border-r border-gray-300 dark:border-gray-600 py-1 bg-gray-200 dark:bg-gray-600 box-border"
                                >
                                    {day.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit', year: 'numeric' })}
                                </div>
                            ))}
                        </div>

                        {/* Row 2: Hours */}
                        <div className="flex border-b border-gray-300 dark:border-gray-600">
                             <div 
                                style={{ width: `${yAxisWidth}px` }} 
                                className="flex-shrink-0 sticky left-0 bg-gray-200 dark:bg-gray-800 border-r border-gray-300 dark:border-gray-600 flex items-center px-3 text-xs font-bold text-gray-700 dark:text-gray-200 z-40"
                            >
                                Atividade
                            </div>
                            {days.map(day => (
                                <React.Fragment key={`hours-${day.toISOString()}`}>
                                    {Array.from({ length: 24 }, (_, i) => (
                                        <div 
                                            key={`${day.toISOString()}-${i}`}
                                            style={{ width: `${hourWidth}px` }}
                                            className="flex-shrink-0 text-center text-[10px] text-gray-500 dark:text-gray-400 border-r border-gray-200 dark:border-gray-600 py-0.5 bg-gray-50 dark:bg-gray-700 box-border"
                                        >
                                            {i.toString().padStart(2, '0')}:00
                                        </div>
                                    ))}
                                </React.Fragment>
                            ))}
                        </div>
                    </div>

                    {/* Chart Body */}
                    <div className="relative">
                         {/* Background Grid & Current Time */}
                         {/* Positioned ABSOLUTE covering the entire width of rows, shifted by yAxisWidth */}
                        <div 
                            className="absolute top-0 bottom-0" 
                            style={{ 
                                left: `${yAxisWidth}px`, 
                                width: `${totalChartWidth}px`, 
                                pointerEvents: 'none',
                                zIndex: 0
                            }}
                        >
                             {/* Draw grid lines for every hour - Exact match with header logic */}
                             {days.map((day, dayIdx) => (
                                <React.Fragment key={`grid-${day.toISOString()}`}>
                                    {Array.from({ length: 24 }, (_, i) => (
                                        <div 
                                            key={`grid-line-${dayIdx}-${i}`}
                                            className={`absolute top-0 bottom-0 border-l box-border ${i === 0 ? 'border-gray-300 dark:border-gray-500' : 'border-gray-100 dark:border-gray-700/50 border-dashed'}`}
                                            style={{ left: `${(dayIdx * 24 + i) * hourWidth}px` }}
                                        ></div>
                                    ))}
                                </React.Fragment>
                             ))}

                            {renderCurrentTimeLine()}
                        </div>

                        {/* Activity Rows */}
                        {sortedActivities.map((activity, index) => (
                            <div 
                                key={activity.id} 
                                style={{ height: `${rowHeight}px` }} 
                                className={`flex items-center border-b border-gray-100 dark:border-gray-700/50 relative hover:bg-blue-50 dark:hover:bg-gray-700/30 transition-colors z-10 ${index % 2 === 0 ? 'bg-transparent' : 'bg-gray-50/30 dark:bg-gray-800/50'}`}
                            >
                                {/* Y Axis Label (Sticky Left) */}
                                <div 
                                    style={{ width: `${yAxisWidth}px` }}
                                    className="flex-shrink-0 h-full px-3 sticky left-0 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-600 flex flex-col justify-center cursor-pointer z-20 group"
                                    title={`${activity.tag} - ${activity.descricao}`}
                                    onClick={() => onEdit(activity)}
                                >
                                    <div className="flex items-center justify-between">
                                        <p className="font-bold truncate text-xs text-gray-800 dark:text-gray-200 group-hover:text-primary-600 transition-colors">{activity.tag}</p>
                                        <div className={`w-2 h-2 rounded-full ${STATUS_COLORS[activity.status]}`}></div>
                                    </div>
                                    {!isCompact && (
                                        <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate mt-0.5">{activity.descricao}</p>
                                    )}
                                </div>

                                {/* Bar Container */}
                                <div className="relative h-full" style={{ width: `${totalChartWidth}px` }}>
                                     <GanttBar 
                                        activity={activity} 
                                        chartStart={chartStart}
                                        hourWidth={hourWidth} 
                                        height={rowHeight}
                                        onClick={() => onEdit(activity)} 
                                    />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import ReactDOM from 'react-dom/client';
import { Header } from './components/Header';
import { DashboardView } from './components/DashboardView';
import { ActivityListView } from './components/ActivityListView';
import { ActivityBoardView } from './components/ActivityBoardView';
import { ActivityGanttView } from './components/ActivityGanttView';
import { ReportView } from './components/ReportView';
import { AuditLogView } from './components/AuditLogView';
import { ManPowerView } from './components/ManPowerView';
import { ActivityCalendarView } from './components/ActivityCalendarView';
import { Modal } from './components/Modal';
import { ActivityForm } from './components/ActivityForm';
import { LoginView } from './components/LoginView';
import { ImportMappingModal } from './components/ImportMappingModal';
import { mockActivities, mockUsers } from './data/mockData';
import { Activity, ViewType, FilterType, ActivityStatus, Criticidade, AuditLogEntry, User, ImportMapping, ImportBatch, Recorrencia, Attachment } from './types';
import { PlusIcon } from './components/icons/PlusIcon';
import { ImageViewerModal } from './components/ImageViewerModal';
import { PhotoIcon } from './components/icons/PhotoIcon';
import { UserIcon } from './components/icons/UserIcon';
import { TrashIcon } from './components/icons/TrashIcon';
import { PencilIcon } from './components/icons/PencilIcon';
import { supabase } from './supabaseClient'; 

const App: React.FC = () => {
    const [theme, setTheme] = useState<'light' | 'dark'>(() => {
        if (typeof window !== 'undefined' && window.localStorage) {
            const storedTheme = window.localStorage.getItem('theme');
            if (storedTheme === 'dark' || storedTheme === 'light') {
                return storedTheme;
            }
        }
        return 'light';
    });

    const [users, setUsers] = useState<User[]>([]);
    const [activities, setActivities] = useState<Activity[]>([]);
    const [importBatches, setImportBatches] = useState<ImportBatch[]>([]);
    const [auditLogs, setAuditLogs] = useState<AuditLogEntry[]>([]);

    const [user, setUser] = useState<User | null>(null);
    const [loginError, setLoginError] = useState<string | undefined>();
    const [currentView, setCurrentView] = useState<ViewType>('dashboard');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
    const [editingActivity, setEditingActivity] = useState<Activity | null>(null);
    const [viewingImage, setViewingImage] = useState<string | null>(null);

    // Status connection
    const [isSupabaseConnected, setIsSupabaseConnected] = useState(false);

    // Import State
    const [isImportModalOpen, setIsImportModalOpen] = useState(false);
    const [excelHeaders, setExcelHeaders] = useState<string[]>([]);
    const [pendingImportData, setPendingImportData] = useState<any[]>([]);
    const [pendingImportFile, setPendingImportFile] = useState<File | null>(null);
    const [editingBatchId, setEditingBatchId] = useState<string | null>(null);
    const [initialMapping, setInitialMapping] = useState<ImportMapping | undefined>(undefined);

    const [filters, setFilters] = useState<FilterType>({ 
        turno: 'all', 
        responsavel: 'all', 
        supervisor: 'all',
        idMp: '',
        onlyMyActivities: false
    });

    const [statusLabels, setStatusLabels] = useState<Record<string, string>>(() => {
        const stored = localStorage.getItem('statusLabels');
        if (stored) return JSON.parse(stored);
        return {
            [ActivityStatus.Open]: 'Aberto',
            [ActivityStatus.NaoExecutado]: 'Não Executado',
            [ActivityStatus.EmProgresso]: 'Em Andamento',
            [ActivityStatus.ExecutadoParcialmente]: 'Parcial',
            [ActivityStatus.Closed]: 'Concluído',
        };
    });

    // --- DATA LOADING & SUPABASE ---

    const logMissingTablesError = () => {
        if (!isSupabaseConnected) return; // Prevent spam
        console.warn("SUPABASE: Tabelas não encontradas. O App funcionará em modo OFFLINE.");
        console.warn("Para corrigir, execute o SQL no editor do Supabase (Ver documentação).");
    };

    useEffect(() => {
        const loadData = async () => {
            // Check connection first
            const { error: healthCheck } = await supabase.from('activities').select('id').limit(1);

            if (healthCheck && healthCheck.code === 'PGRST204') {
               // Ignore specific error logic for now, try catch block below is better
            }

            try {
                // 1. Users
                const { data: usersData, error: usersError } = await supabase.from('app_users').select('*');
                if (usersError) throw usersError;
                if (usersData) setUsers(usersData);

                // 2. Activities
                const { data: activitiesData, error: actError } = await supabase.from('activities').select('*');
                if (actError) throw actError;
                if (activitiesData) {
                    // Flatten JSON data if stored in json_data column, or use direct cols if mapped
                    const parsedActivities = activitiesData.map((row: any) => row.json_data || row);
                    setActivities(parsedActivities);
                }

                // 3. Import Batches
                const { data: batchesData, error: batchError } = await supabase.from('import_batches').select('*');
                if (batchError) throw batchError;
                if (batchesData) {
                    const parsedBatches = batchesData.map((row: any) => row.json_data || row);
                    setImportBatches(parsedBatches);
                }

                setIsSupabaseConnected(true);
                console.log("Conectado ao Supabase.");

            } catch (error: any) {
                // Silent fail to local storage if tables missing
                if (error.message && error.message.includes('relation') && error.message.includes('does not exist')) {
                    setIsSupabaseConnected(false);
                    logMissingTablesError();
                } else {
                    console.error("Erro ao carregar dados do Supabase:", error);
                }

                // Fallback to LocalStorage
                const storedUsers = localStorage.getItem('db_users_secure');
                if (storedUsers) setUsers(JSON.parse(storedUsers));
                else setUsers(mockUsers); // Default mocks

                const storedActivities = localStorage.getItem('db_activities');
                if (storedActivities) setActivities(JSON.parse(storedActivities));
                else setActivities(mockActivities);

                const storedBatches = localStorage.getItem('db_import_batches');
                if (storedBatches) setImportBatches(JSON.parse(storedBatches));
            }
        };

        loadData();
    }, []);

    // --- PERSISTENCE (SUPABASE + LOCAL STORAGE FALLBACK) ---

    // Save to LocalStorage whenever state changes (Offline Backup)
    useEffect(() => {
        if (!isSupabaseConnected) {
            localStorage.setItem('db_users_secure', JSON.stringify(users));
        }
    }, [users, isSupabaseConnected]);

    useEffect(() => {
        if (!isSupabaseConnected) {
            localStorage.setItem('db_activities', JSON.stringify(activities));
        }
    }, [activities, isSupabaseConnected]);

    useEffect(() => {
        if (!isSupabaseConnected) {
            localStorage.setItem('db_import_batches', JSON.stringify(importBatches));
        }
    }, [importBatches, isSupabaseConnected]);


    const saveActivityToSupabase = async (activity: Activity) => {
        if (!isSupabaseConnected) return;
        const cleanActivity = JSON.parse(JSON.stringify(activity));
        const { error } = await supabase.from('activities').upsert({
            id: activity.id,
            json_data: cleanActivity
        });
        if (error) {
            if (error.code === '42501') alert("Erro de Permissão (RLS). Execute o script SQL no Supabase.");
            else if (!error.message.includes("does not exist")) console.error('Error saving activity:', error.message);
        }
    };

    const deleteActivityFromSupabase = async (id: string) => {
        if (!isSupabaseConnected) return;
        await supabase.from('activities').delete().eq('id', id);
    };

    const saveUserToSupabase = async (u: User) => {
        if (!isSupabaseConnected) return;
        const { error } = await supabase.from('app_users').upsert(u);
        if (error) {
             if (error.code === '42501') alert("Erro de Permissão (RLS) ao salvar usuário.");
             else if (!error.message.includes("does not exist")) console.error('Error saving user:', error.message);
        }
    };

    const saveBatchToSupabase = async (batch: ImportBatch) => {
        if (!isSupabaseConnected) return;
        const cleanBatch = JSON.parse(JSON.stringify(batch));
        const { error } = await supabase.from('import_batches').upsert({
            id: batch.id,
            json_data: cleanBatch
        });
        if (error && !error.message.includes("does not exist")) console.error('Error saving batch:', error.message);
    };

    const deleteBatchFromSupabase = async (batchId: string) => {
         if (!isSupabaseConnected) return;
         await supabase.from('import_batches').delete().eq('id', batchId);
    };

    // --- FILE UPLOAD (SUPABASE) ---

    const fileToBase64 = (file: File): Promise<string> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.readAsDataURL(file);
            reader.onload = () => resolve(reader.result as string);
            reader.onerror = error => reject(error);
        });
    };

    const uploadFileToSupabase = async (file: File, folder: string = 'misc'): Promise<string | null> => {
        if (!isSupabaseConnected) {
            return await fileToBase64(file); // Fallback offline
        }

        try {
            const fileName = `${Date.now()}_${file.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
            const filePath = `${folder}/${fileName}`;

            const { data, error } = await supabase.storage
                .from('app-files')
                .upload(filePath, file);

            if (error) {
                console.warn("Upload failed (Storage not configured?), falling back to Base64.", error.message);
                return await fileToBase64(file);
            }

            const { data: publicData } = supabase.storage
                .from('app-files')
                .getPublicUrl(filePath);

            return publicData.publicUrl;
        } catch (e) {
            console.error("Upload exec error:", e);
            return await fileToBase64(file);
        }
    };

    // --- THEME ---
    useEffect(() => {
        const root = window.document.documentElement;
        root.classList.remove(theme === 'light' ? 'dark' : 'light');
        root.classList.add(theme);
        localStorage.setItem('theme', theme);
    }, [theme]);

    useEffect(() => {
        localStorage.setItem('statusLabels', JSON.stringify(statusLabels));
    }, [statusLabels]);

    const toggleTheme = () => {
        setTheme(prevTheme => (prevTheme === 'light' ? 'dark' : 'light'));
    };

    // --- LOGIN LOGIC ---

    const handleLogin = (usernameInput: string, passwordInput: string) => {
        const foundUser = users.find(u => 
            u.username.toLowerCase() === usernameInput.toLowerCase() && 
            u.password === passwordInput
        );
        if (foundUser) {
            setUser(foundUser);
            setLoginError(undefined);
        } else {
            setLoginError('Usuário ou senha incorretos.');
        }
    };

    const handleRegister = async (newUser: User) => {
        const exists = users.some(u => u.username.toLowerCase() === newUser.username.toLowerCase());
        if (exists) {
            alert("Usuário já existe.");
            return;
        }

        setUsers(prev => [...prev, newUser]);
        setUser(newUser);
        await saveUserToSupabase(newUser);
    };

    const handleRecoverPassword = (username: string, name: string, newPassword: string): boolean => {
        const userIdx = users.findIndex(u => 
            u.username.toLowerCase() === username.toLowerCase() && 
            u.name.toLowerCase() === name.toLowerCase()
        );

        if (userIdx !== -1) {
            const updatedUser = { ...users[userIdx], password: newPassword };
            const newUsers = [...users];
            newUsers[userIdx] = updatedUser;
            setUsers(newUsers);
            saveUserToSupabase(updatedUser);
            return true;
        }
        return false; 
    };

    const handleRecoverUsername = (name: string): string | null => {
        const found = users.find(u => u.name.toLowerCase() === name.toLowerCase());
        return found ? found.username : null;
    };

    const handleLogout = async () => {
        setUser(null);
    };

    // --- ACTION HANDLERS ---

    const handleBackgroundUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0] && user) {
            const file = e.target.files[0];
            const publicUrl = await uploadFileToSupabase(file, `users/${user.username}`);
            if (publicUrl) {
                const updatedUser = { ...user, backgroundImage: publicUrl };
                setUser(updatedUser);
                setUsers(prev => prev.map(u => u.username === user.username ? updatedUser : u));
                await saveUserToSupabase(updatedUser);
            }
        }
    };

