import { TrashIcon } from './icons/TrashIcon';
import { getCriticidadeClasses } from '../utils/styleUtils';

interface KanbanCardProps {
    activity: Activity;
    onEdit: (activity: Activity) => void;
    onUpdateStatus: (activityId: string, status: ActivityStatus) => void;
    onDelete?: (activityId: string) => void;
    onImageClick: (imageUrl: string) => void;
}

const ImagePreview: React.FC<{ images: Attachment[], label: string, onClick: (url: string) => void }> = ({ images, label, onClick }) => {
    const firstImage = images[0];
    const count = images.length;

    return (
        <div className="relative cursor-pointer" onClick={() => onClick(firstImage.url)}>
            <img
                src={firstImage.url}
                alt={firstImage.name}
                className="w-full h-40 object-cover"
                title={`Clique para ampliar: ${firstImage.name}`}
            />
            <p className="absolute bottom-1 left-1 bg-black bg-opacity-50 text-white text-xs font-semibold px-2 py-1 rounded">
                {label} {count > 1 && `(+${count - 1})`}
            </p>
        </div>
    );
}


export const KanbanCard: React.FC<KanbanCardProps> = ({ activity, onEdit, onDelete, onImageClick }) => {
    const hasBefore = activity.beforeImage && activity.beforeImage.length > 0;
    const hasAfter = activity.afterImage && activity.afterImage.length > 0;
    const hasImages = hasBefore || hasAfter;

    const handleDragStart = (e: React.DragEvent) => {
        e.dataTransfer.setData("text/plain", activity.id);
        e.dataTransfer.effectAllowed = "move";
    };

    return (
        <div 
            draggable
            onDragStart={handleDragStart}
            className="bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow-md border-l-4 border-primary-500 overflow-hidden flex flex-col cursor-grab active:cursor-grabbing hover:shadow-lg transition-all"
        >

            {hasImages && (
                <div className={`grid ${hasBefore && hasAfter ? 'grid-cols-2' : 'grid-cols-1'}`}>
                    {hasBefore && <ImagePreview images={activity.beforeImage!} label="Antes" onClick={onImageClick} />}
                    {hasAfter && <ImagePreview images={activity.afterImage!} label="Depois" onClick={onImageClick} />}
                </div>
            )}

            <div className="p-4 space-y-3">
                <div className="flex justify-between items-start">
                    <p className="font-semibold text-gray-800 dark:text-white flex-1 pr-2 text-sm">{activity.descricao}</p>
                     <div className="flex space-x-1 flex-shrink-0">
                        <button onClick={() => onEdit(activity)} className="text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400">
                            <PencilIcon className="w-4 h-4" />
                        </button>
                        {onDelete && (
                            <button onClick={() => onDelete(activity.id)} className="text-gray-500 hover:text-red-500 dark:text-gray-400">
                                <TrashIcon className="w-4 h-4" />
                            </button>
                        )}
                     </div>
                </div>

                <div className="flex items-center justify-between">
                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase ${getCriticidadeClasses(activity.criticidade)}`}>
                        {activity.criticidade}
                    </span>
                     <span className="text-[10px] bg-gray-200/80 dark:bg-gray-600/80 px-2 py-0.5 rounded text-gray-600 dark:text-gray-300 font-mono">
                        {activity.tag}
                    </span>
                </div>

                <div className="text-xs text-gray-600 dark:text-gray-300 space-y-2 pt-1 border-t border-gray-200/50 dark:border-gray-600/50 mt-2">
                    <div className="flex items-center space-x-2 pt-2">
                        <UserIcon className="w-3 h-3" />
                        <span className="truncate">{activity.responsavel}</span>
                    </div>
                    {activity.supervisor && (
                         <div className="flex items-center space-x-2 text-gray-500 dark:text-gray-400">
                            <span className="w-3 h-3 flex items-center justify-center font-bold text-[8px]">S</span>
                            <span className="truncate">Sup: {activity.supervisor}</span>
                        </div>
                    )}
                    <div className="flex items-center space-x-2">
                        <ClockIcon className="w-3 h-3" />
                        <span>{new Date(activity.horaInicio).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(activity.horaFim).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                     <div className="flex items-center space-x-2">
                        {hasImages && <CameraIcon className="w-3 h-3 text-blue-500"/>}
                        <PaperClipIcon className="w-3 h-3" />
                        <span>{activity.attachments?.length || 0}</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { type Activity, ActivityStatus } from '../types';
import { PencilIcon } from './icons/PencilIcon';
import { PaperClipIcon } from './icons/PaperClipIcon';
import { CameraIcon } from './icons/CameraIcon';
import { ArrowsUpDownIcon } from './icons/ArrowsUpDownIcon';
import { TrashIcon } from './icons/TrashIcon';
import { getStatusClasses, getCriticidadeClasses, getStatusLabel } from '../utils/styleUtils';

interface ActivityListViewProps {
    activities: Activity[];
    onEdit: (activity: Activity) => void;
    onUpdateStatus: (activityId: string, status: ActivityStatus) => void;
    onDelete?: (activityId: string) => void;
    customStatusLabels?: Record<string, string>;
}

type SortDirection = 'asc' | 'desc';

interface SortConfig {
    key: keyof Activity | 'statusLabel' | null;
    direction: SortDirection;
}

export const ActivityListView: React.FC<ActivityListViewProps> = ({ activities, onEdit, onUpdateStatus, onDelete, customStatusLabels = {} }) => {
    // Sorting State
    const [sortConfig, setSortConfig] = useState<SortConfig>({ key: null, direction: 'asc' });

    // Resizing State
    const [columnWidths, setColumnWidths] = useState<Record<string, number>>({
        tag: 90,
        descricao: 280,
        responsavel: 130,
        supervisor: 130,
        turno: 70,
        horario: 110,
        duracao: 70,
        criticidade: 90,
        status: 130,
        anexos: 60,
        acoes: 70
    });

    const resizingRef = useRef<{ key: string; startX: number; startWidth: number } | null>(null);

    // Current time for conditional formatting
    const [now, setNow] = useState(new Date());

    useEffect(() => {
        // Update "now" every minute to refresh conditional formatting
        const timer = setInterval(() => setNow(new Date()), 60000);
        return () => clearInterval(timer);
    }, []);

    const handleStatusChange = (activityId: string, newStatus: string) => {
        onUpdateStatus(activityId, newStatus as ActivityStatus);
    };

    const handleSort = (key: keyof Activity | 'statusLabel') => {
        setSortConfig(prev => ({
            key,
            direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedActivities = useMemo(() => {
        if (!sortConfig.key) return activities;

        return [...activities].sort((a, b) => {
            let aValue: any = sortConfig.key === 'statusLabel' 
                ? getStatusLabel(a.status, customStatusLabels) 
                : a[sortConfig.key as keyof Activity];

            let bValue: any = sortConfig.key === 'statusLabel'
                ? getStatusLabel(b.status, customStatusLabels)
                : b[sortConfig.key as keyof Activity];

            // Handle undefined/null
            if (aValue === undefined || aValue === null) aValue = '';
            if (bValue === undefined || bValue === null) bValue = '';

            // Handle Date strings
            if (sortConfig.key === 'horaInicio' || sortConfig.key === 'horaFim') {
                return sortConfig.direction === 'asc' 
                    ? new Date(aValue).getTime() - new Date(bValue).getTime()
                    : new Date(bValue).getTime() - new Date(aValue).getTime();
            }

            // Handle Strings
            if (typeof aValue === 'string' && typeof bValue === 'string') {
                return sortConfig.direction === 'asc'
                    ? aValue.localeCompare(bValue)
                    : bValue.localeCompare(aValue);
            }

            return 0;
        });
    }, [activities, sortConfig, customStatusLabels]);

    // Resizing Logic
    const handleMouseDown = (e: React.MouseEvent, key: string) => {
        e.preventDefault();
        resizingRef.current = {
            key,
            startX: e.pageX,
            startWidth: columnWidths[key] || 100
        };
        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (resizingRef.current) {
            const { key, startX, startWidth } = resizingRef.current;
            const diff = e.pageX - startX;
            const newWidth = Math.max(40, startWidth + diff); 
            setColumnWidths(prev => ({ ...prev, [key]: newWidth }));
        }
    };

    const handleMouseUp = () => {
        resizingRef.current = null;
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };

    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };
    }, []);

    const Th: React.FC<{ id: string; label: string; sortKey?: keyof Activity | 'statusLabel' }> = ({ id, label, sortKey }) => (
        <th 
            scope="col" 
            className="relative px-3 py-2 select-none border-r border-gray-200/50 dark:border-gray-700/50 last:border-r-0 group whitespace-nowrap"
            style={{ width: columnWidths[id] }}
        >
            <div 
                className={`flex items-center space-x-1 ${sortKey ? 'cursor-pointer hover:text-primary-600' : ''}`}
                onClick={() => sortKey && handleSort(sortKey)}
            >
                <span className="truncate">{label}</span>
                {sortKey && (
                    <span className={`transition-opacity ${sortConfig.key === sortKey ? 'opacity-100 text-primary-600' : 'opacity-30 group-hover:opacity-70'}`}>
                         <ArrowsUpDownIcon className="w-3 h-3" />
                    </span>
                )}
            </div>
            <div 
                className="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-blue-500 z-10"
                onMouseDown={(e) => handleMouseDown(e, id)}
            ></div>
        </th>
    );

    if (activities.length === 0) {
        return <div className="text-center p-8 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow">Nenhuma atividade encontrada.</div>;
    }

    return (
        <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md rounded-lg shadow overflow-x-auto">
            <table className="w-full text-xs text-left text-gray-500 dark:text-gray-400 table-fixed">
                <thead className="text-xs text-gray-700 uppercase bg-gray-50/50 dark:bg-gray-700/50 dark:text-gray-300">
                    <tr>
                        <Th id="tag" label="TAG" sortKey="tag" />
                        <Th id="descricao" label="Descrição" sortKey="descricao" />
                        <Th id="responsavel" label="Responsável" sortKey="responsavel" />
                        <Th id="supervisor" label="Supervisor" sortKey="supervisor" />
                        <Th id="turno" label="Turno" sortKey="turno" />
                        <Th id="horario" label="Horário" sortKey="horaInicio" />
                        <Th id="duracao" label="Duração" sortKey="duracao" />
                        <Th id="criticidade" label="Criticidade" sortKey="criticidade" />
                        <Th id="status" label="Status" sortKey="statusLabel" />
                        <Th id="anexos" label="Anexos" />
                        <Th id="acoes" label="Ações" />
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-100/50 dark:divide-gray-700/50">
                    {sortedActivities.map(activity => {
                        // Conditional Formatting Logic: Open AND Start Time < Now
                        const isOverdue = activity.status === ActivityStatus.Open && new Date(activity.horaInicio) < now;

                        return (
                            <tr key={activity.id} className="bg-transparent hover:bg-gray-50/50 dark:hover:bg-gray-700/30 transition-colors">
                                <td 
                                    className="px-3 py-1.5 font-medium text-gray-900 dark:text-white truncate overflow-hidden cursor-pointer hover:text-primary-600 hover:underline"
                                    onClick={() => onEdit(activity)}
                                    title="Clique para editar"
                                >
                                    {activity.tag}
                                </td>
                                <td 
                                    className="px-3 py-1.5 truncate overflow-hidden cursor-pointer hover:text-primary-600" 
                                    title={activity.descricao}
                                    onClick={() => onEdit(activity)}
                                >
                                    {activity.descricao}
                                </td>
                                <td className="px-3 py-1.5 truncate overflow-hidden">{activity.responsavel}</td>
                                <td className="px-3 py-1.5 truncate overflow-hidden">{activity.supervisor}</td>
                                <td className="px-3 py-1.5 truncate overflow-hidden text-center">{activity.turno}</td>
                                <td className={`px-3 py-1.5 truncate overflow-hidden ${isOverdue ? 'text-red-600 font-bold dark:text-red-400' : ''}`}>
                                    {new Date(activity.horaInicio).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(activity.horaFim).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </td>
                                <td className="px-3 py-1.5 truncate overflow-hidden text-center">{activity.duracao}</td>
                                <td className="px-3 py-1.5">
                                    <span className={`px-1.5 py-0.5 rounded-full text-[10px] font-semibold border ${getCriticidadeClasses(activity.criticidade)}`}>
                                        {activity.criticidade}
                                    </span>
                                </td>
                                <td className="px-3 py-1.5">
                                    <select 
                                        value={activity.status}
                                        onChange={(e) => handleStatusChange(activity.id, e.target.value)}
                                        className={`w-full p-0.5 rounded text-[10px] focus:ring-primary-500 focus:border-primary-500 cursor-pointer ${getStatusClasses(activity.status, true)}`}
                                    >
                                        {Object.values(ActivityStatus).map(s => (
                                            <option key={s} value={s} className="text-gray-800 bg-white">
                                                {getStatusLabel(s, customStatusLabels)}
                                            </option>
                                        ))}
                                    </select>
                                </td>
                                <td className="px-3 py-1.5">
                                    <div className="flex items-center justify-center space-x-1 text-gray-500 dark:text-gray-400">
                                        {(activity.beforeImage || activity.afterImage) && (
                                            <span title="Contém imagem de antes/depois">
                                                <CameraIcon className="w-4 h-4 text-blue-500" />
                                            </span>
                                        )}
                                        {(activity.attachments?.length || 0) > 0 && (
                                            <div className="flex items-center">
                                                <PaperClipIcon className="w-3.5 h-3.5" />
                                                <span className="ml-0.5 text-[10px]">{activity.attachments?.length}</span>
                                            </div>
                                        )}
                                    </div>
                                </td>
                                <td className="px-3 py-1.5 text-center">
                                    <div className="flex items-center justify-center space-x-2">
                                        <button onClick={() => onEdit(activity)} className="text-primary-600 hover:text-primary-800 dark:text-primary-500 dark:hover:text-primary-300 transition-colors" title="Editar">
                                            <PencilIcon className="w-4 h-4"/>
                                        </button>
                                        {onDelete && (
                                            <button onClick={() => onDelete(activity.id)} className="text-red-500 hover:text-red-700 transition-colors" title="Excluir">
                                                <TrashIcon className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>
    );
};

import React, { useMemo, useState } from 'react';
import type { Activity } from '../types';
import { ActivityStatus, Criticidade } from '../types';
import { getStatusLabel } from '../utils/styleUtils';
import { ChartBarIcon } from './icons/ChartBarIcon';
import { ChartPieIcon } from './icons/ChartPieIcon';
import { 
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
    PieChart, Pie, Cell, LineChart, Line 
} from 'recharts';

interface DashboardViewProps {
    activities: Activity[];
    customStatusLabels?: Record<string, string>;
}

const STATUS_COLORS: { [key in ActivityStatus]: string } = {
    [ActivityStatus.Open]: '#374151', // Gray 700
    [ActivityStatus.NaoExecutado]: '#dc2626', // Red 600
    [ActivityStatus.EmProgresso]: '#2563eb', // Blue 600
    [ActivityStatus.ExecutadoParcialmente]: '#eab308', // Yellow 500
    [ActivityStatus.Closed]: '#16a34a', // Green 600
};

const CRITICIDADE_COLORS: { [key in Criticidade]: string } = {
    [Criticidade.Baixa]: '#22c55e',   // Green
    [Criticidade.Normal]: '#3b82f6',  // Blue
    [Criticidade.Alta]: '#f97316',    // Orange
    [Criticidade.Urgente]: '#ef4444', // Red
};

type ChartType = 'bar' | 'pie' | 'line';

export const DashboardView: React.FC<DashboardViewProps> = ({ activities, customStatusLabels = {} }) => {
    const [statusChartType, setStatusChartType] = useState<ChartType>('bar');
    const [critChartType, setCritChartType] = useState<ChartType>('pie');

    // --- Data Preparation ---

    const totalActivities = activities.length;

    // 1. Status Data
    const statusData = useMemo(() => {
        const counts = activities.reduce((acc, activity) => {
            acc[activity.status] = (acc[activity.status] || 0) + 1;
            return acc;
        }, {} as Record<ActivityStatus, number>);

        return Object.entries(counts).map(([key, value]) => ({ 
            name: getStatusLabel(key as ActivityStatus, customStatusLabels),
            originalKey: key,
            value: value as number,
            color: STATUS_COLORS[key as ActivityStatus] || '#9ca3af'
        })).sort((a, b) => b.value - a.value); // Sort by count descending
    }, [activities, customStatusLabels]);

    // 2. Criticality Data
    const critData = useMemo(() => {
        const counts = activities.reduce((acc, activity) => {
            acc[activity.criticidade] = (acc[activity.criticidade] || 0) + 1;
            return acc;
        }, {} as Record<Criticidade, number>);

        return Object.entries(counts).map(([key, value]) => ({
            name: key.charAt(0).toUpperCase() + key.slice(1),
            originalKey: key,
            value: value as number,
            color: CRITICIDADE_COLORS[key as Criticidade] || '#9ca3af'
        }));
    }, [activities]);

    const completedActivities = activities.filter(a => a.status === ActivityStatus.Closed).length;
    const progressPercentage = totalActivities > 0 ? Math.round((completedActivities / totalActivities) * 100) : 0;

    // --- Render Helpers ---

    if (activities.length === 0) {
        return (
            <div className="flex items-center justify-center h-96 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow-lg">
                <p className="text-lg text-gray-500 dark:text-gray-400">Nenhuma atividade encontrada para os filtros selecionados.</p>
            </div>
        );
    }

    // Custom Tooltip
    const CustomTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            const data = payload[0].payload;
            const percent = ((data.value / totalActivities) * 100).toFixed(1);
            return (
                <div className="bg-white/95 dark:bg-gray-800/95 p-3 rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 backdrop-blur-sm">
                    <p className="font-bold text-gray-800 dark:text-white mb-1">{data.name}</p>
                    <div className="flex items-center space-x-4 text-sm">
                        <span className="text-gray-600 dark:text-gray-300">Quantidade: <span className="font-semibold">{data.value}</span></span>
                        <span className="text-gray-600 dark:text-gray-300">Porcentagem: <span className="font-semibold text-blue-600 dark:text-blue-400">{percent}%</span></span>
                    </div>
                </div>
            );
        }
        return null;
    };

    // Chart Toggle Component
    const ChartToggle = ({ current, onChange }: { current: ChartType, onChange: (t: ChartType) => void }) => (
        <div className="flex bg-gray-100/50 dark:bg-gray-700/50 rounded-lg p-1 space-x-1">
            {[
                { type: 'bar', label: 'Barras', icon: <ChartBarIcon className="w-4 h-4"/> },
                { type: 'pie', label: 'Pizza', icon: <ChartPieIcon className="w-4 h-4"/> },
                { type: 'line', label: 'Linhas', icon: <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg> }
            ].map((opt) => (
                <button
                    key={opt.type}
                    onClick={() => onChange(opt.type as ChartType)}
                    className={`flex items-center space-x-1 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                        current === opt.type 
                            ? 'bg-white/80 dark:bg-gray-600/80 text-primary-600 dark:text-white shadow-sm' 
                            : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
                    }`}
                    title={`Visualizar como ${opt.label}`}
                >
                    {opt.icon}
                    <span className="hidden sm:inline">{opt.label}</span>
                </button>
            ))}
        </div>
    );

    const renderChart = (type: ChartType, data: any[]) => {
        if (type === 'bar') {
            return (
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={data} margin={{ top: 20, right: 30, left: 0, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} strokeOpacity={0.1} />
                        <XAxis dataKey="name" tick={{fill: '#6b7280', fontSize: 11}} axisLine={false} tickLine={false} />
                        <YAxis tick={{fill: '#6b7280', fontSize: 11}} axisLine={false} tickLine={false} allowDecimals={false} />
                        <Tooltip content={<CustomTooltip />} cursor={{fill: 'rgba(0,0,0,0.05)'}} />
                        <Bar dataKey="value" radius={[4, 4, 0, 0]} animationDuration={1000}>
                            {data.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
            );
        }
        if (type === 'pie') {
            return (
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                            data={data}
                            dataKey="value"
                            nameKey="name"
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={100}
                            paddingAngle={2}
                            animationDuration={1000}
                        >
                            {data.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={2} stroke="#fff" />
                            ))}
                        </Pie>
                        <Tooltip content={<CustomTooltip />} />
                        <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{fontSize: '11px'}} />
                    </PieChart>
                </ResponsiveContainer>
            );
        }
        if (type === 'line') {
            return (
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data} margin={{ top: 20, right: 30, left: 10, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.1} />
                        <XAxis dataKey="name" tick={{fill: '#6b7280', fontSize: 11}} />
                        <YAxis tick={{fill: '#6b7280', fontSize: 11}} allowDecimals={false} />
                        <Tooltip content={<CustomTooltip />} />
                        <Line type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={3} dot={{r: 6, strokeWidth: 2}} activeDot={{r: 8}} animationDuration={1000} />
                    </LineChart>
                </ResponsiveContainer>
            );
        }
    };

    return (
        <div className="space-y-6 text-gray-900 dark:text-gray-100">
            {/* Progress Bar Section */}
            <div className="bg-white/70 dark:bg-gray-900/80 backdrop-blur-md p-6 rounded-lg shadow-lg border border-gray-200/50 dark:border-gray-700/50">
                <div className="flex justify-between items-end mb-4">
                    <div>
                        <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Dashboard Geral</h2>
                        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Visão geral do progresso e distribuição das atividades.</p>
                    </div>
                    <div className="text-right">
                        <span className="text-4xl font-bold text-primary-600 dark:text-primary-400">{progressPercentage}%</span>
                        <span className="text-sm text-gray-500 dark:text-gray-400 block">Concluído</span>
                    </div>
                </div>
                <div className="relative h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                    <div 
                        style={{ width: `${progressPercentage}%` }} 
                        className="absolute top-0 left-0 h-full bg-gradient-to-r from-primary-500 to-green-500 transition-all duration-1000 ease-out rounded-full"
                    ></div>
                </div>
