            </div>
        </div>
    );
};

import React, { useEffect, useState, useRef, useMemo } from 'react';
import type { Activity } from '../types';
import { ActivityStatus } from '../types';

interface ActivityGanttViewProps {
    activities: Activity[];
    onEdit: (activity: Activity) => void;
}

const STATUS_COLORS: { [key in ActivityStatus]: string } = {
    [ActivityStatus.Open]: 'bg-gray-600',
    [ActivityStatus.NaoExecutado]: 'bg-red-600',
    [ActivityStatus.EmProgresso]: 'bg-blue-600',
    [ActivityStatus.ExecutadoParcialmente]: 'bg-yellow-500',
    [ActivityStatus.Closed]: 'bg-green-600',
};

const GanttBar: React.FC<{ activity: Activity, chartStart: number, hourWidth: number, height: number, onClick: () => void }> = ({ activity, chartStart, hourWidth, height, onClick }) => {
    const start = new Date(activity.horaInicio).getTime();
    const end = new Date(activity.horaFim).getTime();

    // Calculate position relative to chart start
    // Ensure we account for strict pixel arithmetic to align with the grid
    const diffMs = start - chartStart;
    const durationMs = end - start;

    // 1 hour = hourWidth pixels
    // 1 ms = hourWidth / 3600000 pixels
    const pxPerMs = hourWidth / 3600000;

    const left = diffMs * pxPerMs;
    const width = Math.max(durationMs * pxPerMs, 4); // Min width 4px

    const barColor = STATUS_COLORS[activity.status] || 'bg-gray-500';

    return (
        <div 
            className={`absolute top-1/2 -translate-y-1/2 rounded-sm opacity-90 hover:opacity-100 transition-all flex items-center px-2 text-[10px] font-medium text-white shadow-sm ${barColor} cursor-pointer hover:ring-1 hover:ring-white hover:z-10 overflow-hidden whitespace-nowrap`}
            style={{ 
                left: `${left}px`, 
                width: `${width}px`, 
                height: `${height * 0.7}px`, // Bar uses 70% of row height
            }}
            title={`${activity.tag} - ${activity.descricao}\n${new Date(activity.horaInicio).toLocaleString()} - ${new Date(activity.horaFim).toLocaleString()}`}
            onClick={(e) => {
                e.stopPropagation();
                onClick();
            }}
        >
            {width > 40 && <span className="truncate">{activity.tag}</span>}
        </div>
    );
};

export const ActivityGanttView: React.FC<ActivityGanttViewProps> = ({ activities, onEdit }) => {
    const [currentTime, setCurrentTime] = useState(new Date());
    const [hourWidth, setHourWidth] = useState(60); // Zoom level
    const [isCompact, setIsCompact] = useState(false); // Row height toggle
    const containerRef = useRef<HTMLDivElement>(null);

    const rowHeight = isCompact ? 28 : 45; 
    const yAxisWidth = 220; 

    useEffect(() => {
        const timer = setInterval(() => {
            setCurrentTime(new Date());
        }, 60000);
        return () => clearInterval(timer);
    }, []);

    // --- Timeline Calculation ---
    const { chartStart, chartEnd, days } = useMemo(() => {
        if (activities.length === 0) {
            const now = new Date();
            const start = new Date(now); start.setHours(0,0,0,0);
            const end = new Date(now); end.setHours(23,59,59,999);
            return { chartStart: start.getTime(), chartEnd: end.getTime(), days: [start] };
        }

        const startTimes = activities.map(a => new Date(a.horaInicio).getTime());
        const endTimes = activities.map(a => new Date(a.horaFim).getTime());

        const minTime = Math.min(...startTimes);
        const maxTime = Math.max(...endTimes);

        // Start at 00:00 of the first day
        const startDate = new Date(minTime);
        startDate.setHours(0, 0, 0, 0);

        // End at 23:59 of the last day
        const endDate = new Date(maxTime);
        endDate.setHours(23, 59, 59, 999);

        // Generate array of days
        const daysArr = [];
        let current = new Date(startDate);
        while (current <= endDate) {
            daysArr.push(new Date(current));
            current.setDate(current.getDate() + 1);
        }

        return { chartStart: startDate.getTime(), chartEnd: endDate.getTime(), days: daysArr };
    }, [activities]);

    const totalHours = days.length * 24;
    const totalChartWidth = totalHours * hourWidth;
    const pxPerMs = hourWidth / 3600000;

    // Scroll to Now
    const scrollToNow = () => {
        if (containerRef.current) {
            const nowMs = new Date().getTime();
            if (nowMs >= chartStart && nowMs <= chartEnd) {
                const diff = nowMs - chartStart;
                const left = diff * pxPerMs;
                const scrollLeft = left - (containerRef.current.clientWidth / 2) + yAxisWidth;
                containerRef.current.scrollTo({ left: Math.max(0, scrollLeft), behavior: 'smooth' });
            } else {
                alert("A data atual está fora do intervalo de atividades exibido.");
            }
        }
    };

    // --- Render Helpers ---

    // Current Time Line
    const renderCurrentTimeLine = () => {
        const nowMs = currentTime.getTime();
        if (nowMs < chartStart || nowMs > chartEnd) return null;

        const left = (nowMs - chartStart) * pxPerMs;
        const label = currentTime.toLocaleTimeString([], {hour: '2-digit', minute: '2-digit'});

        return (
            <div 
                className="absolute top-0 bottom-0 w-[2px] bg-red-500 z-20 shadow-[0_0_4px_rgba(239,68,68,0.6)] pointer-events-none" 
                style={{ 
                    left: `${left}px`,
                    transform: 'translateX(-50%)' 
                }}
            >
                <div className="absolute -top-0 -translate-x-1/2 bg-red-600 text-white text-[9px] px-1 py-0.5 rounded-b font-bold whitespace-nowrap z-30">
                    {label}
                </div>
            </div>
        );
    };

    if (activities.length === 0) {
        return <div className="text-center p-8 bg-white/70 dark:bg-gray-800/70 backdrop-blur-md rounded-lg shadow text-gray-800 dark:text-gray-200">Nenhuma atividade para exibir no gráfico de Gantt.</div>;
    }

    // Sort strictly by Date first.
    // Changing status should NOT move the activity if date is same.
    const sortedActivities = [...activities].sort((a,b) => {
        return new Date(a.horaInicio).getTime() - new Date(b.horaInicio).getTime();
    });

    return (
        <div className="flex flex-col h-[80vh] bg-white/70 dark:bg-gray-900/80 backdrop-blur-md rounded-lg shadow border border-gray-200/50 dark:border-gray-700/50">

            {/* Controls Toolbar */}
            <div className="p-2 border-b border-gray-200/50 dark:border-gray-700/50 flex items-center justify-between bg-gray-50/50 dark:bg-gray-800/50 rounded-t-lg">
                <div className="flex items-center space-x-4">
                    <div className="flex items-center space-x-1 bg-white/50 dark:bg-gray-700/50 rounded-md border dark:border-gray-600 p-0.5">
                        <button 
                            onClick={() => setHourWidth(prev => Math.max(20, prev - 10))}
                            className="px-2 py-1 text-xs font-bold text-gray-600 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-600 rounded"
                            title="Diminuir Zoom"
                        >
                            -
                        </button>
                        <span className="text-xs text-gray-500 dark:text-gray-400 min-w-[60px] text-center">Zoom: {hourWidth}px</span>
                        <button 
                            onClick={() => setHourWidth(prev => Math.min(200, prev + 10))}
                            className="px-2 py-1 text-xs font-bold text-gray-600 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-600 rounded"
                            title="Aumentar Zoom"
                        >
                            +
                        </button>
                    </div>

                    <label className="flex items-center cursor-pointer space-x-2 text-xs text-gray-700 dark:text-gray-300">
                        <input 
                            type="checkbox" 
                            checked={isCompact} 
                            onChange={(e) => setIsCompact(e.target.checked)} 
                            className="rounded text-primary-600 focus:ring-primary-500 dark:bg-gray-700 dark:border-gray-600"
                        />
                        <span>Compacto</span>
                    </label>
                </div>

                <button 
                    onClick={scrollToNow}
                    className="px-3 py-1 text-xs bg-red-100/80 text-red-700 dark:bg-red-900/50 dark:text-red-300 rounded border border-red-200 dark:border-red-800 hover:bg-red-200 transition-colors"
                >
                    Ir para Agora
                </button>
            </div>

            {/* Main Chart Area */}
            <div className="flex-1 overflow-auto relative" ref={containerRef}>
                {/* 
                   KEY LAYOUT FIX:
                   Ensure the container for rows and grid is exactly the same width.
                   Grid acts as absolute background to the relative content container.
                */}
                <div className="relative inline-block" style={{ minWidth: '100%' }}>

                    {/* Header Container (Sticky) */}
                    <div className="sticky top-0 z-30 bg-gray-100/90 dark:bg-gray-700/90 shadow-sm backdrop-blur-sm">

                        {/* Row 1: Days */}
                        <div className="flex border-b border-gray-300 dark:border-gray-600">
                            {/* Empty corner for Y axis */}
                            <div 
                                style={{ width: `${yAxisWidth}px` }} 
                                className="flex-shrink-0 sticky left-0 bg-gray-200/90 dark:bg-gray-800/90 border-r border-gray-300 dark:border-gray-600 z-40 backdrop-blur-sm"
                            ></div>

                            {/* Days Loop */}
                            {days.map(day => (
                                <div 
                                    key={day.toISOString()}
                                    style={{ width: `${24 * hourWidth}px` }}
                                    className="flex-shrink-0 text-center text-xs font-bold text-gray-700 dark:text-gray-200 border-r border-gray-300 dark:border-gray-600 py-1 bg-gray-200/80 dark:bg-gray-600/80 box-border"
                                >
                                    {day.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit', year: 'numeric' })}
                                </div>
                            ))}
                        </div>

                        {/* Row 2: Hours */}
                        <div className="flex border-b border-gray-300 dark:border-gray-600">
                             <div 
                                style={{ width: `${yAxisWidth}px` }} 
                                className="flex-shrink-0 sticky left-0 bg-gray-200/90 dark:bg-gray-800/90 border-r border-gray-300 dark:border-gray-600 flex items-center px-3 text-xs font-bold text-gray-700 dark:text-gray-200 z-40 backdrop-blur-sm"
                            >
                                Atividade
                            </div>
                            {days.map(day => (
                                <React.Fragment key={`hours-${day.toISOString()}`}>
                                    {Array.from({ length: 24 }, (_, i) => (
                                        <div 
                                            key={`${day.toISOString()}-${i}`}
                                            style={{ width: `${hourWidth}px` }}
                                            className="flex-shrink-0 text-center text-[10px] text-gray-500 dark:text-gray-400 border-r border-gray-200 dark:border-gray-600 py-0.5 bg-gray-50/50 dark:bg-gray-700/50 box-border"
                                        >
                                            {i.toString().padStart(2, '0')}:00
                                        </div>
                                    ))}
                                </React.Fragment>
                            ))}
                        </div>
                    </div>

                    {/* Chart Body */}
                    <div className="relative">
                         {/* Background Grid & Current Time */}
                         {/* Positioned ABSOLUTE covering the entire width of rows, shifted by yAxisWidth */}
                        <div 
                            className="absolute top-0 bottom-0" 
                            style={{ 
                                left: `${yAxisWidth}px`, 
                                width: `${totalChartWidth}px`, 
                                pointerEvents: 'none',
                                zIndex: 0
                            }}
                        >
                             {/* Draw grid lines for every hour - Exact match with header logic */}
                             {days.map((day, dayIdx) => (
                                <React.Fragment key={`grid-${day.toISOString()}`}>
                                    {Array.from({ length: 24 }, (_, i) => (
                                        <div 
                                            key={`grid-line-${dayIdx}-${i}`}
                                            className={`absolute top-0 bottom-0 border-l box-border ${i === 0 ? 'border-gray-300 dark:border-gray-500' : 'border-gray-100 dark:border-gray-700/50 border-dashed'}`}
                                            style={{ left: `${(dayIdx * 24 + i) * hourWidth}px` }}
                                        ></div>
                                    ))}
                                </React.Fragment>
                             ))}

                            {renderCurrentTimeLine()}
                        </div>

                        {/* Activity Rows */}
                        {sortedActivities.map((activity, index) => (
                            <div 
                                key={activity.id} 
                                style={{ height: `${rowHeight}px` }} 
                                className={`flex items-center border-b border-gray-100 dark:border-gray-700/50 relative hover:bg-blue-50/50 dark:hover:bg-gray-700/30 transition-colors z-10 ${index % 2 === 0 ? 'bg-transparent' : 'bg-gray-50/30 dark:bg-gray-800/30'}`}
                            >
                                {/* Y Axis Label (Sticky Left) */}
                                <div 
                                    style={{ width: `${yAxisWidth}px` }}
                                    className="flex-shrink-0 h-full px-3 sticky left-0 bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm border-r border-gray-200 dark:border-gray-600 flex flex-col justify-center cursor-pointer z-20 group"
                                    title={`${activity.tag} - ${activity.descricao}`}
                                    onClick={() => onEdit(activity)}
                                >
                                    <div className="flex items-center justify-between">
                                        <p className="font-bold truncate text-xs text-gray-800 dark:text-gray-200 group-hover:text-primary-600 transition-colors">{activity.tag}</p>
                                        <div className={`w-2 h-2 rounded-full ${STATUS_COLORS[activity.status]}`}></div>
                                    </div>
                                    {!isCompact && (
                                        <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate mt-0.5">{activity.descricao}</p>
                                    )}
                                </div>

                                {/* Bar Container */}
                                <div className="relative h-full" style={{ width: `${totalChartWidth}px` }}>
                                     <GanttBar 
                                        activity={activity} 
                                        chartStart={chartStart}
                                        hourWidth={hourWidth} 
                                        height={rowHeight}
                                        onClick={() => onEdit(activity)} 
                                    />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import type { Activity } from '../types';
import { getStatusClasses, getStatusLabel } from '../utils/styleUtils';
import { Attachment } from '../types';

interface ReportViewProps {
    activities: Activity[];
    onImageClick: (imageUrl: string) => void;
    customStatusLabels?: Record<string, string>;
}

const formatTime = (isoString?: string) => {
    if (!isoString) return 'N/A';
    return new Date(isoString).toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
};

const ImageCarousel: React.FC<{ images: Attachment[], label: string, onImageClick: (url: string) => void }> = ({ images, label, onImageClick }) => {
    const [index, setIndex] = useState(0);

    const prev = (e: React.MouseEvent) => {
        e.stopPropagation();
        setIndex((i) => (i === 0 ? images.length - 1 : i - 1));
    };

    const next = (e: React.MouseEvent) => {
        e.stopPropagation();
        setIndex((i) => (i === images.length - 1 ? 0 : i + 1));
    };

    const current = images[index];

    if (images.length === 0) {
        return (
            <div>
                <p className="font-medium mb-1 text-sm text-gray-600 dark:text-gray-400">{label}</p>
                <div className="w-full aspect-square flex items-center justify-center bg-gray-100 dark:bg-gray-700/50 rounded-md border dark:border-gray-600 text-gray-500 text-xs italic">
                    Sem imagem
                </div>
            </div>
        );
    }

    return (
        <div>
            <div className="flex justify-between items-center mb-1">
                <p className="font-medium text-sm text-gray-600 dark:text-gray-400">{label}</p>
                {images.length > 1 && (
                    <span className="text-[10px] bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5 rounded text-gray-600 dark:text-gray-300">
                        {index + 1}/{images.length}
                    </span>
                )}
            </div>
            <div 
                className="relative group aspect-square w-full bg-gray-100 dark:bg-gray-800 rounded-md border dark:border-gray-600 overflow-hidden cursor-pointer"
                onClick={() => onImageClick(current.url)}
            >
                <img 
                    src={current.url} 
                    alt={`${label} ${index + 1}`} 
                    className="w-full h-full object-cover" 
                />

                {/* Hover Overlay */}
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                     {/* Zoom Icon hint */}
                     <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8 text-white opacity-0 group-hover:opacity-100 transition-opacity drop-shadow-md">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607zM10.5 7.5v6m3-3h-6" />
                    </svg>
                </div>

                {/* Arrows */}
                {images.length > 1 && (
                    <>
                        <button 
                            onClick={prev}
                            className="absolute left-2 top-1/2 -translate-y-1/2 p-1.5 bg-black/40 hover:bg-black/60 text-white rounded-full backdrop-blur-sm transition-all opacity-0 group-hover:opacity-100 z-10"
                            title="Anterior"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
                            </svg>
                        </button>
                        <button 
                            onClick={next}
                            className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-black/40 hover:bg-black/60 text-white rounded-full backdrop-blur-sm transition-all opacity-0 group-hover:opacity-100 z-10"
                            title="Próxima"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                            </svg>
                        </button>
                    </>
                )}
            </div>
        </div>
    );
};

